import { z } from 'zod';

// DAT schemas
export const createDatSessionSchema = z.object({
  body: z.object({
    enrollmentId: z.string().min(1, 'Mã enrollment bắt buộc'),
    date: z.string().min(1, 'Ngày bắt buộc'),
    timeStart: z.string().min(1, 'Giờ bắt đầu bắt buộc'),
    timeEnd: z.string().min(1, 'Giờ kết thúc bắt buộc'),
    duration: z.number().optional(),
    km: z.number().optional(),
  }),
});

// Health check schema
export const updateHealthCheckSchema = z.object({
  body: z.object({
    enrollmentId: z.string().min(1),
    status: z.enum(['Chờ khám', 'Đủ điều kiện', 'Không đủ điều kiện']),
    date: z.string().optional(),
    hospital: z.string().min(1, 'Phòng khám/bệnh viện bắt buộc'),
    note: z.string().optional(),
  }),
});

// Bulk update schema
export const bulkUpdateCourseStatusSchema = z.object({
  body: z.object({
    courseIds: z.array(z.string()).min(1, 'Phải chọn ít nhất 1 khóa'),
    newStatus: z.enum(['draft', 'ongoing', 'completed', 'canceled']),
  }),
});

// Payment schemas
export const createPaymentSchema = z.object({
  body: z.object({
    studentId: z.string().min(1, 'Mã học viên bắt buộc'),
    amount: z.number().positive('Số tiền phải > 0'),
    phase: z.string().optional(),
    method: z.enum(['cash', 'transfer', 'other']).optional(),
  }),
});

import { DatRepository } from '@/infrastructure/repositories/dat.repository';
import { IDatSession } from '@/infrastructure/database/models/dat_session.model';
import { StudentRepository } from '@/infrastructure/repositories/student.repository';
import { ExamRepository } from '@/infrastructure/repositories/exam.repository';

export class DatService {
  private datRepository: DatRepository;
  private studentRepository: StudentRepository;
  private examRepository: ExamRepository;

  constructor() {
    this.datRepository = new DatRepository();
    this.studentRepository = new StudentRepository();
    this.examRepository = new ExamRepository();
  }

  async addDatSession(data: Partial<IDatSession>): Promise<IDatSession> {
    return await this.datRepository.create(data);
  }

  async getStudentDatSessions(courseStudentId: string): Promise<IDatSession[]> {
    return await this.datRepository.findByCourseStudent(courseStudentId);
  }

  async getStudentDatStats(courseStudentId: string) {
    return await this.datRepository.getStatsByStudent(courseStudentId);
  }

  async getDatAnalytics(currentUser?: any) {
    const [datStats, studentStats, examStats] = await Promise.all([
      this.datRepository.getDatStats(currentUser),
      this.studentRepository.getStats(currentUser),
      this.examRepository.getStats('graduation' as any, currentUser),
    ]);

    // Format chart data (Ensure all 6 months are present)
    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const chartData = [];
    for (let i = 0; i < 6; i++) {
      const d = new Date();
      d.setMonth(d.getMonth() - (5 - i));
      const m = d.getMonth() + 1;
      const y = d.getFullYear();
      const monthlyData = datStats.monthlyKm || [];
      const found = monthlyData.find((item: any) => item._id.month === m && item._id.year === y);
      chartData.push({
        label: monthNames[m - 1],
        value: found ? Math.round(found.total_km) : 0,
      });
    }

    const passRate =
      examStats && examStats.total > 0 ? Math.round(((examStats.passed || 0) / examStats.total) * 100) : 0;

    return {
      monthly_growth: chartData,
      global_stats: {
        total_students: studentStats?.total || 0,
        active_students: studentStats?.active || 0,
        completed_km_count: datStats.completedKmCount || 0,
        pass_rate: passRate,
      },
    };
  }
}

import type {} from '../types/express.d';
import { Request, Response } from 'express';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import { DatService } from '@/application/services/dat.service';

const datService = new DatService();

/**
 * Get DAT Analytics for the Progress Page
 */
export const getDatAnalytics = catchAsync(async (req: Request, res: Response) => {
  const analytics = await datService.getDatAnalytics((req as any).user);
  res.statusSuccess(analytics, 'DAT Analytics retrieved successfully');
});

/**
 * Add a new DAT Session
 */
export const addDatSession = catchAsync(async (req: Request, res: Response) => {
  const session = await datService.addDatSession(req.body);
  res.statusSuccess(session, 'DAT Session added successfully');
});

/**
 * Get DAT Sessions for a specific enrollment
 */
export const getStudentDatSessions = catchAsync(async (req: Request, res: Response) => {
  const { enrollmentId } = req.params;
  const sessions = await datService.getStudentDatSessions(enrollmentId as string);
  res.statusSuccess(sessions, 'Student DAT sessions retrieved successfully');
});

import mongoose, { Schema, Document, Types } from 'mongoose';

export enum DatSessionType {
  Cabin = 'cabin',
  Dat = 'dat',
}

export interface IDatSession extends Document {
  course_student_id: Types.ObjectId;
  session_type: DatSessionType;
  start_time: Date;
  end_time: Date;
  distance_km: number;
  rfid_card?: string;
  notes?: string;
  created_at: Date;
  updated_at: Date;
}

const DatSessionSchema = new Schema<IDatSession>(
  {
    course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', required: true, index: true },
    session_type: { type: String, enum: Object.values(DatSessionType), required: true },
    start_time: { type: Date, required: true },
    end_time: { type: Date, required: true },
    distance_km: { type: Number, required: true, default: 0 },
    rfid_card: { type: String },
    notes: { type: String },
  },
  {
    timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
    versionKey: false,
  },
);

DatSessionSchema.index({ session_type: 1 });
DatSessionSchema.index({ start_time: -1 });

export const DatSessionModel =
  mongoose.models.DatSession || mongoose.model<IDatSession>('DatSession', DatSessionSchema);

import { DatSessionModel, IDatSession } from '../database/models/dat_session.model';
import mongoose from 'mongoose';

export class DatRepository {
  async create(data: Partial<IDatSession>): Promise<IDatSession> {
    if (data.course_student_id && typeof data.course_student_id === 'string') {
      data.course_student_id = new mongoose.Types.ObjectId(data.course_student_id) as any;
    }
    return await DatSessionModel.create(data);
  }

  async findByCourseStudent(courseStudentId: string): Promise<IDatSession[]> {
    if (!mongoose.Types.ObjectId.isValid(courseStudentId)) return [];
    return await DatSessionModel.find({
      course_student_id: new mongoose.Types.ObjectId(courseStudentId),
    })
      .sort({ start_time: -1 })
      .exec();
  }

  async delete(id: string): Promise<IDatSession | null> {
    if (!mongoose.Types.ObjectId.isValid(id)) return null;
    return await DatSessionModel.findByIdAndDelete(new mongoose.Types.ObjectId(id)).exec();
  }

  async getStatsByStudent(courseStudentId: string): Promise<{ total_km: number; total_minutes: number }> {
    if (!mongoose.Types.ObjectId.isValid(courseStudentId)) return { total_km: 0, total_minutes: 0 };

    const results = await DatSessionModel.aggregate([
      { $match: { course_student_id: new mongoose.Types.ObjectId(courseStudentId), session_type: 'dat' } },
      {
        $group: {
          _id: null,
          total_km: { $sum: '$distance_km' },
          total_minutes: {
            $sum: {
              $divide: [
                { $subtract: ['$end_time', '$start_time'] },
                1000 * 60, // Convert ms to minutes
              ],
            },
          },
        },
      },
    ]);

    return {
      total_km: results[0]?.total_km || 0,
      total_minutes: results[0]?.total_minutes || 0,
    };
  }

  async getDatStats(currentUser?: any): Promise<any> {
    const match: any = { session_type: 'dat' };

    if (currentUser?.role === 'teacher') {
      const teacherId = currentUser.id || currentUser._id;
      // eslint-disable-next-line @typescript-eslint/no-require-imports
      const { CourseStudentModel } = require('../database/models/course_student.model');
      const assignedEnrollmentIds = await CourseStudentModel.find({ teacher_id: teacherId }).distinct('_id').exec();
      match.course_student_id = { $in: assignedEnrollmentIds };
    }

    const sixMonthsAgo = new Date();
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 5);
    sixMonthsAgo.setDate(1);
    sixMonthsAgo.setHours(0, 0, 0, 0);

    const [monthlyKm, completedKmStats] = await Promise.all([
      DatSessionModel.aggregate([
        { $match: { ...match, start_time: { $gte: sixMonthsAgo } } },
        {
          $group: {
            _id: {
              month: { $month: '$start_time' },
              year: { $year: '$start_time' },
            },
            total_km: { $sum: '$distance_km' },
          },
        },
        { $sort: { '_id.year': 1, '_id.month': 1 } },
      ]),
      DatSessionModel.aggregate([
        { $match: match },
        { $group: { _id: '$course_student_id', total_km: { $sum: '$distance_km' } } },
        { $match: { total_km: { $gte: 810 } } },
        { $count: 'count' },
      ]),
    ]);

    return {
      monthlyKm,
      completedKmCount: completedKmStats[0]?.count || 0,
    };
  }
}

